function load$Grid(g) {
  g._$k = [];
  g._$e = g._getColumnOrder('type');
  g._$i = g._getColumnOrder('ma_nkt');
  g._$t = g._getColumnOrder('tag');
  g.add_onResponseComplete(on$Grid&Controller;$ResponseComplete);
  g.add_commandEvent(on$Grid&Controller;$ExecuteCommand);
}
function scatter$Grid(g) {fill$Grid(g, true);}
function dispose$Grid(g) {
  try {g.remove_commandEvent(on$Grid&Controller;$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$Grid&Controller;$ResponseComplete);} catch (ex) {}
}
function on$Grid&Controller;$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'Register':
    case 'VoucherBookTemplatesCreate':
      if (isCheck$Grid(g) && isCheck$Type(g)){
        g._$s = g._$k.join(',');
        show$Form(g, '&Controller;Create');
      }
      break;
    case 'VoucherBookTemplatesUpdateStatus':
      if (isCheck$Grid(g) && isCheck$Type(g)){
        g._$s = g._$k.join(',');
        show$Form$Edit(g, '&Controller;UpdateStatus');
      }
      break;
    case 'VoucherBookTemplatesDelete':
      if (isCheck$Grid(g) && isCheck$Type(g)){
        g._$s = g._$k.join(',');
        show$Form$Delete(g, '&Controller;Delete');
      }
      break;
    default:
      break;
  }
}
function show$Form(g, c) {(g._authorize == 1) ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess"));}
function show$Form$Edit(g, c) {g._authorizeEdit == 1 ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess")) : $message.show(g._denyMessage);}
function show$Form$Delete(g, c) {g._authorizeDelete == 1 ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess")) : $message.show(g._denyMessage);}
function on$Grid&Controller;$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'VoucherBookTemplatesCreate':
      refresh$Grid(g);
      g._$k = [];
      break;
    case 'VoucherBookTemplatesUpdateStatus':
      refresh$Grid(g);
      g._$k = [];
      break;
    case 'VoucherBookTemplatesDelete':
      refresh$Grid(g);
      g._$k = [];
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function beforeDrillDown(g) {g._args.cancelEvent = !($func.trim(g._getItemValue(g._activeRow, g._activeColumn)));}
function formatDateView(c) {return String.format('{0}/{1}/{2}', c.substring(6, 8), c.substring(4, 6), c.substring(0, 4));}
function isCheck$Type(g) {
  var c = '0', e = '';
  for (var r = 1; r <= g._rowCount; r++) {
    if (g._getItemValue(r, g._$t)) {
      e = e + g._getItemValue(r, g._$e) + String.fromCharCode(253);
      g._$st = g._getItemValue(r, g._$e);
    }
  }
  var a = e.substring(0, e.length - 1).split(String.fromCharCode(253));
  if (a.length > 1) {
    for (var i = 0; i < a.length - 1; i++) {
      for (var j = i + 1; j < a.length; j++) {
        if a[j] != a[i] {
          c = '1';
          break;
        }
      }
      if c == '1' break;
    }
  }
  var msg = (g._language == 'v' ? 'Bản ghi được chọn không cùng loại.' : 'The selected records are not the same type.');
  if (c == '1') {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    return false;
  }
  return true;
}
function isCheck$Grid(g) {
  var msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  if (g._$k.length == 0) {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    return false;
  }
  return true;
}
function fill$Grid(g, f) {
  if (f && g._$k.length == 0) return;
   for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r, true), i = Array.indexOf(g._$k, k);
    g._setItemValue(r, g._$t, (i > -1));
  }
}
function toggle$Grid(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11));
  for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r, true), i = Array.indexOf(g._$k, k);
    if (i == -1) {Array.add(g._$k, k);}
    else {Array.removeAt(g._$k, i);}
    g._setItemValue(r, g._$t, (i == -1));
  }
  g._focusWhenTabChanged();
}
function onChange$SelectedValue(o) {
  var r = $func.getLocationCell(o)[0], g = $find(o.id.split('_inputCell_')[0]), k = row$Key(g, r, true), i = Array.indexOf(g._$k, k);
  if (i == -1) {Array.add(g._$k, k);}
  else {Array.removeAt(g._$k, i);}
}
function refresh$Grid(g) {
  if (g._$k.length > 0) {
    g.goToPage(-1);
    return false;
  }
}
function row$Key(g, r, c) {return g._getItemValue(r, g._$i);}

function setObjectFormHidden(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      grandNode = o.parentNode.parentNode;
      if (!v) $common.setVisible(o.parentNode.parentNode.parentNode, false);
    }
  }
}
function checkPeriod(f, c, u){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var e = null, name = $func.trim(a[i]), o = f.getItem(name), c = o.value, l = o.field.Label;
    if (c.length > 0) {
      if (u == 1 && (c < 1 || c > 12)) return showError(f, l, name);
    }
  }
  return true;
}
function showError(f, l, name) {
  var id = f.get_id(), msg = (f._language == 'v' ? 'Trường <span class="Highlight">{0}</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">{0}</span> must not be blank or has invalid value.');
  msg = String.format(msg, l);
  f._checked = false;
  $func.hideWait(id);
  $message.show(msg, String.format('$find(\'{0}\').focus(\'' + name + '\');', id));
  return false;
}
function refresh$Page(f) {
  var g = f.grid, o = $find(g._id);
  o.goToPage(-1);
  g._$k = [];
}
